external_knowledge:
- 'Barack Obama' refers to a specific candidate in the database; 
- A 'positive level of support' means the support percentage is greater than 0; 
- 'SurveyUSA' is a polling organization; 
- 'most recent survey' implies the latest end date.

sql:
SELECT DISTINCT pollster
FROM polls
WHERE state = 'New York';

SELECT SUM(undecided) AS total_undecided_voters
FROM polls
WHERE pollster = 'PollingOrg';
